import anthropic
import json
import uuid
from functools import wraps

# Agent Card with authentication requirement:
AGENT_CARD_WITH_AUTH = {
    "name": "SecureResearchAgent",
    "description": "Research agent requiring API key authentication.",
    "url": "https://agents.example.com/secure-research",
    "authentication": {
        "schemes": ["ApiKey"],
        "apiKeyHeader": "X-Agent-Api-Key",
    },
    "skills": [
        {
            "id": "research",
            "name": "Research",
            "description": "Search for factual information.",
            "inputModes": ["text"],
            "outputModes": ["text"],
        }
    ],
}

# Valid API keys (in production: store in a secrets manager, not in code)
VALID_API_KEYS = {"sk-research-abc123", "sk-research-def456"}

def require_api_key(fn):
    """Decorator that checks the X-Agent-Api-Key header before processing."""
    @wraps(fn)
    def wrapper(request_headers: dict, *args, **kwargs):
        api_key = request_headers.get("X-Agent-Api-Key", "")
        if api_key not in VALID_API_KEYS:
            return {"error": "Unauthorized", "status": 401}
        return fn(request_headers, *args, **kwargs)
    return wrapper

@require_api_key
def handle_task_request(request_headers: dict, task_payload: dict) -> dict:
    """
    A2A task endpoint (POST /tasks/send) with API key auth.
    In production: this is an HTTP handler, not a plain function.
    """
    client = anthropic.Anthropic()
    task_id = str(uuid.uuid4())
    message = task_payload.get("message", {}).get("parts", [{}])[0].get("text", "")

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system="You are a research agent. Answer concisely.",
        messages=[{"role": "user", "content": message}],
    )
    answer = resp.content[0].text.strip()
    return {
        "id": task_id,
        "status": {"state": "completed"},
        "artifacts": [{"type": "text", "data": answer}],
    }

# Caller with valid API key:
headers = {"X-Agent-Api-Key": "sk-research-abc123"}
result = handle_task_request(
    headers,
    {"message": {"parts": [{"text": "What is the speed of sound in air?"}]}},
)
print(result["status"]["state"])   # completed
print(result["artifacts"][0]["data"])

# Caller with invalid key:
bad_result = handle_task_request(
    {"X-Agent-Api-Key": "wrong-key"},
    {"message": {"parts": [{"text": "Any question"}]}},
)
print(bad_result)  # {"error": "Unauthorized", "status": 401}
